// Use the real inventory response if the API answered; otherwise fall back
// to an embedded mock snapshot so the workflow is demoable end-to-end.
const resp = $input.first().json;
if (resp && resp.buckets) {
  return [{ json: { ...resp, source: 'inventory_api' } }];
}

return [{ json: {
  source: 'embedded_mock',
  snapshot_at: new Date().toISOString(),
  account_id: '123456789012',
  buckets: [
    { name: 'corp-public-website-assets', region: 'eu-west-1', public_access_block: false, acl_public_read: true, encryption: 'AES256', tags: { approved_public: 'true' } },
    { name: 'finance-quarterly-exports', region: 'eu-west-1', public_access_block: false, acl_public_read: true, encryption: null, tags: {} },
    { name: 'app-logs-prod', region: 'eu-central-1', public_access_block: true, acl_public_read: false, encryption: null, tags: {} },
    { name: 'data-lake-raw', region: 'eu-central-1', public_access_block: true, acl_public_read: false, encryption: 'aws:kms', tags: {} }
  ],
  iam_policies: [
    { name: 'AdminBreakGlass', attached_to: ['role/break-glass'], document: { Statement: [{ Effect: 'Allow', Action: '*', Resource: '*' }] } },
    { name: 'CiDeployPolicy', attached_to: ['user/ci-deployer'], document: { Statement: [{ Effect: 'Allow', Action: ['s3:*'], Resource: '*' }] } },
    { name: 'ReadOnlyAnalytics', attached_to: ['group/analysts'], document: { Statement: [{ Effect: 'Allow', Action: ['s3:GetObject'], Resource: 'arn:aws:s3:::data-lake-raw/*' }] } }
  ],
  iam_users: [
    { name: 'ci-deployer', mfa_enabled: false, access_key_age_days: 412, console_access: false },
    { name: 'j.smith', mfa_enabled: true, access_key_age_days: 45, console_access: true },
    { name: 'contractor-temp', mfa_enabled: false, access_key_age_days: 12, console_access: true }
  ],
  security_groups: [
    { id: 'sg-0aa11bb22cc33dd44', name: 'bastion-ssh', rules: [{ port: 22, cidr: '203.0.113.0/24' }] },
    { id: 'sg-0ee55ff66aa77bb88', name: 'legacy-rdp', rules: [{ port: 3389, cidr: '0.0.0.0/0' }] }
  ]
} }];

// Policy-as-code checks. Each violation becomes one finding item.
// Drift detection: workflowStaticData remembers finding IDs from previous
// runs, so re-detections are labeled 'existing' and fresh ones 'NEW'.
const inv = $input.first().json;
const findings = [];
const add = (rule, severity, resource, detail, remediation) => findings.push({
  finding_id: `${rule}:${resource}`,
  rule, severity, resource, detail, remediation,
  account_id: inv.account_id ?? 'unknown',
});

for (const b of inv.buckets ?? []) {
  const publicBucket = b.acl_public_read && !b.public_access_block;
  const approvedPublic = String(b.tags?.approved_public) === 'true';
  if (publicBucket && !approvedPublic) {
    add('S3-001-public-bucket', 'critical', `s3://${b.name}`,
      'Bucket is publicly readable and has no approved_public exception tag.',
      'Enable Public Access Block or tag with an approved exception after review.');
  }
  if (!b.encryption) {
    add('S3-002-no-encryption', 'medium', `s3://${b.name}`,
      'Default encryption is disabled.',
      'Enable SSE-S3 (AES256) or SSE-KMS.');
  }
}

for (const p of inv.iam_policies ?? []) {
  const stmts = p.document?.Statement ?? [];
  for (const s of stmts) {
    const actions = Array.isArray(s.Action) ? s.Action : [s.Action];
    const wildcardAction = actions.includes('*');
    const wildcardResource = s.Resource === '*' || (Array.isArray(s.Resource) && s.Resource.includes('*'));
    if (s.Effect === 'Allow' && wildcardAction && wildcardResource) {
      add('IAM-001-full-admin', 'critical', `policy/${p.name}`,
        `Allows Action:* on Resource:* (attached to: ${(p.attached_to ?? []).join(', ')}).`,
        'Scope to least privilege; if break-glass, require MFA condition + alerting on use.');
    } else if (s.Effect === 'Allow' && wildcardResource && actions.some(a => String(a).endsWith(':*'))) {
      add('IAM-002-service-wildcard', 'high', `policy/${p.name}`,
        `Service-level wildcard (${actions.join(', ')}) on all resources.`,
        'Constrain Resource to specific ARNs.');
    }
  }
}

for (const u of inv.iam_users ?? []) {
  if (u.console_access && !u.mfa_enabled) {
    add('IAM-003-no-mfa', 'high', `user/${u.name}`,
      'Console access without MFA.',
      'Enforce MFA via IAM policy condition or SSO migration.');
  }
  if ((u.access_key_age_days ?? 0) > 365) {
    add('IAM-004-stale-key', 'medium', `user/${u.name}`,
      `Access key is ${u.access_key_age_days} days old.`,
      'Rotate the key; prefer short-lived credentials.');
  }
}

for (const sg of inv.security_groups ?? []) {
  for (const r of sg.rules ?? []) {
    if (r.cidr === '0.0.0.0/0' && [22, 3389].includes(r.port)) {
      add('NET-001-mgmt-open-world', 'critical', `${sg.id} (${sg.name})`,
        `Port ${r.port} open to 0.0.0.0/0.`,
        'Restrict to VPN/bastion CIDRs or use SSM Session Manager.');
    }
  }
}

// Drift labeling via static data (survives between executions)
const sd = $getWorkflowStaticData('global');
const known = sd.known_findings ?? {};
const nowSeen = {};
for (const f of findings) {
  f.status = known[f.finding_id] ? 'existing' : 'NEW';
  f.first_seen = known[f.finding_id] ?? new Date().toISOString();
  nowSeen[f.finding_id] = f.first_seen;
}
const resolved = Object.keys(known).filter(id => !nowSeen[id]);
sd.known_findings = nowSeen;

if (findings.length === 0) {
  return [{ json: { no_findings: true, resolved_since_last_run: resolved, inventory_source: inv.source } }];
}
return findings.map(f => ({ json: { ...f, resolved_since_last_run: resolved, inventory_source: inv.source } }));

// Build one HTML drift report from all findings, grouped by severity.
const items = $input.all().map(i => i.json);
const order = { critical: 0, high: 1, medium: 2, low: 3 };
items.sort((a, b) => (order[a.severity] ?? 9) - (order[b.severity] ?? 9));
const counts = items.reduce((m, f) => { m[f.severity] = (m[f.severity] ?? 0) + 1; return m; }, {});
const newCount = items.filter(f => f.status === 'NEW').length;
const resolved = items[0]?.resolved_since_last_run ?? [];

const sevBadge = s => ({ critical: '#c0392b', high: '#e67e22', medium: '#f1c40f', low: '#95a5a6' }[s] ?? '#95a5a6');
const rows = items.map(f => `<tr>
  <td style="padding:6px;border:1px solid #ddd;"><b style="color:${sevBadge(f.severity)}">${f.severity.toUpperCase()}</b></td>
  <td style="padding:6px;border:1px solid #ddd;">${f.status === 'NEW' ? '🆕 NEW' : 'existing'}</td>
  <td style="padding:6px;border:1px solid #ddd;"><code>${f.rule}</code></td>
  <td style="padding:6px;border:1px solid #ddd;"><code>${f.resource}</code></td>
  <td style="padding:6px;border:1px solid #ddd;">${f.detail}<br/><i>Fix: ${f.remediation}</i></td>
</tr>`).join('\n');

const html = `<h2>Cloud Misconfiguration Drift Report</h2>
<p>Generated ${new Date().toISOString()} · source: ${items[0]?.inventory_source ?? 'n/a'}</p>
<p><b>${items.length}</b> open findings (${newCount} new this run) — critical: ${counts.critical ?? 0}, high: ${counts.high ?? 0}, medium: ${counts.medium ?? 0}. Resolved since last run: ${resolved.length ? resolved.join(', ') : 'none'}.</p>
<table style="border-collapse:collapse;font-family:sans-serif;font-size:13px;">
<tr><th>Severity</th><th>Drift</th><th>Rule</th><th>Resource</th><th>Detail</th></tr>
${rows}
</table>`;

return [{ json: { html, total: items.length, new_count: newCount, counts, subject: `[CloudSec] ${items.length} open misconfigs (${newCount} new, ${counts.critical ?? 0} critical)` } }];
